SELECT AVG(access_count) 
FROM (
  SELECT user_id, COUNT(*) as access_count
  FROM access_logs
  GROUP BY user_id
) AS subquery;

SELECT company_name 
FROM stocks 
WHERE stock_id IN (SELECT stock_id FROM stock_prices WHERE price_id > 0);

SELECT AVG(access_count) AS average_access_count
FROM (
  SELECT user_id, COUNT(*) AS access_count
  FROM access_logs
  GROUP BY user_id
);

SELECT AVG(open_price), AVG(high_price)
FROM stock_prices
WHERE price_id > 500 AND timestamp BETWEEN '2020-01-01' AND '2020-12-31';
